char sa[26],sb[26];

int main()
{

	int len,n,s[101];
	scanf("%d",&n);
	for(int j=1;j<=n;j++)
	{
		scanf("%s%s",sa,sb);
		if(sa[0]==sb[0])
		{
			s[j]=1;
		}
		if(sa[0]=='R'&&sb[0]=='S')
		{
			s[j]=2;
		}
