		{
			s[j]=3;
		}
		if(sa[0]=='R'&&sb[0]=='P')
		{
			s[j]=3;
		}
	}
	for(int i=1;i<=n;i++)
		{
			if(s[i]==1)
			{
				printf("Tie\n");
			}
			if(s[i]==2)
			{
				printf("Player1\n");
			}
			if(s[i]==3)
			{
				printf("Player2\n");
			}
		}
	return 0;
}
